// Config : comptes Meta Ads à scanner + période glissante.
//
// date_preset=last_7d → à chaque run on recalcule les 7 derniers jours
// (Meta rétro-corrige les attributions jusqu'à J-28).
//
// BACKFILL MANUEL :
//   Passer BACKFILL_MODE à true ci-dessous → date_preset='maximum' (tout l'historique)
//   Lancer 1 run manuel, puis REMETTRE à false AVANT d'activer le cron quotidien.

const BACKFILL_MODE = false;

const ORG_ID = '3c68193e-783b-4aa9-bc0d-fb2ce21e99b1';

const accounts = [
  { id: 'act_1147055617398773', name: 'Mayer Energie Clim' },
  { id: 'act_1198344052455745', name: 'Mayer Energie Poêle' },
];

const datePreset = BACKFILL_MODE ? 'maximum' : 'last_7d';

return accounts.map((acc) => ({
  json: {
    org_id: ORG_ID,
    ad_account_id: acc.id,
    ad_account_name: acc.name,
    date_preset: datePreset,
  },
}));

// Normalise les 4 réponses en rows prêtes pour la RPC d'upsert.
// Retourne UN SEUL item { rows: [...] } que le node HTTP transmet tel quel.

const accountCtx = $('Loop Accounts').item.json;
const campaignInsights = $('Fetch Insights (Campaign)').first().json.data || [];
const adsetInsights = $('Fetch Insights (Adset)').first().json.data || [];
const campaignMetaRaw = $('Fetch Campaign Status').first().json.data || [];
const adsetMetaRaw = $('Fetch Adset Status').first().json.data || [];

const toCents = (v) => (v == null || v === '' ? 0 : Math.round(parseFloat(v) * 100));
const toInt = (v) => (v == null || v === '' ? 0 : parseInt(v, 10) || 0);
const toFloat = (v) => (v == null || v === '' ? null : parseFloat(v));

// Meta expose plusieurs action_type pour le MÊME lead (onsite_conversion.lead_grouped,
// lead, offsite_complete_registration_add_meta_leads...). On prend le MAX des 3 types
// représentatifs pour éviter le double/triple comptage.
const LEAD_ACTION_TYPES = [
  'onsite_conversion.lead_grouped',
  'lead',
  'offsite_conversion.fb_pixel_lead',
];
const extractLeads = (actions) => {
  if (!Array.isArray(actions)) return 0;
  let max = 0;
  for (const type of LEAD_ACTION_TYPES) {
    const v = actions
      .filter((a) => a.action_type === type)
      .reduce((sum, a) => sum + (parseInt(a.value, 10) || 0), 0);
    if (v > max) max = v;
  }
  return max;
};

const statusByCampaign = new Map(campaignMetaRaw.map((c) => [c.id, c]));
const statusByAdset = new Map(adsetMetaRaw.map((a) => [a.id, a]));

// Budget courant : renseigné UNIQUEMENT sur le jour du fetch (today)
// pour préserver l'historique réel.
const todayISO = new Date().toISOString().slice(0, 10);

// CBO vs ABO : si le budget campagne est 0, on somme les budgets des adsets
// de cette campagne (ABO = Ad Set Budget Optimization).
const adsetBudgetByCampaign = new Map();
for (const a of adsetMetaRaw) {
  const camp = a.campaign_id;
  if (!camp) continue;
  const bucket = adsetBudgetByCampaign.get(camp) || { daily: 0, lifetime: 0 };
  bucket.daily += toInt(a.daily_budget);
  bucket.lifetime += toInt(a.lifetime_budget);
  adsetBudgetByCampaign.set(camp, bucket);
}

const effectiveCampaignBudget = (campMeta) => {
  const cboDaily = toInt(campMeta.daily_budget);
  const cboLifetime = toInt(campMeta.lifetime_budget);
  if (cboDaily > 0 || cboLifetime > 0) {
    return { daily: cboDaily, lifetime: cboLifetime, remaining: toInt(campMeta.budget_remaining) };
  }
  const aboSum = adsetBudgetByCampaign.get(campMeta.id) || { daily: 0, lifetime: 0 };
  return { daily: aboSum.daily, lifetime: aboSum.lifetime, remaining: null };
};

const rows = [];

for (const r of campaignInsights) {
  const meta = statusByCampaign.get(r.campaign_id) || {};
  const isToday = r.date_start === todayISO;
  const budget = isToday ? effectiveCampaignBudget(meta) : null;
  rows.push({
    org_id: accountCtx.org_id,
    ad_account_id: accountCtx.ad_account_id,
    ad_account_name: accountCtx.ad_account_name,
    entity_level: 'campaign',
    entity_id: r.campaign_id,
    entity_name: r.campaign_name || meta.name,
    entity_status: meta.effective_status || meta.status,
    parent_campaign_id: null,
    parent_campaign_name: null,
    parent_adset_id: null,
    parent_adset_name: null,
    campaign_objective: r.objective || meta.objective,
    date_start: r.date_start,
    spend_cents: toCents(r.spend),
    impressions: toInt(r.impressions),
    reach: toInt(r.reach),
    clicks: toInt(r.clicks),
    ctr: toFloat(r.ctr),
    cpm_cents: toCents(r.cpm),
    cpc_cents: toCents(r.cpc),
    frequency: toFloat(r.frequency),
    leads_meta: extractLeads(r.actions),
    daily_budget_cents: budget ? budget.daily : null,
    lifetime_budget_cents: budget ? budget.lifetime : null,
    budget_remaining_cents: budget ? budget.remaining : null,
    raw_payload: r,
    fetched_at: new Date().toISOString(),
  });
}

for (const r of adsetInsights) {
  const adsetMeta = statusByAdset.get(r.adset_id) || {};
  const campMeta = statusByCampaign.get(r.campaign_id) || {};
  const isToday = r.date_start === todayISO;
  rows.push({
    org_id: accountCtx.org_id,
    ad_account_id: accountCtx.ad_account_id,
    ad_account_name: accountCtx.ad_account_name,
    entity_level: 'adset',
    entity_id: r.adset_id,
    entity_name: r.adset_name || adsetMeta.name,
    entity_status: adsetMeta.effective_status || adsetMeta.status,
    parent_campaign_id: r.campaign_id,
    parent_campaign_name: r.campaign_name || campMeta.name,
    parent_adset_id: null,
    parent_adset_name: null,
    campaign_objective: campMeta.objective,
    date_start: r.date_start,
    spend_cents: toCents(r.spend),
    impressions: toInt(r.impressions),
    reach: toInt(r.reach),
    clicks: toInt(r.clicks),
    ctr: toFloat(r.ctr),
    cpm_cents: toCents(r.cpm),
    cpc_cents: toCents(r.cpc),
    frequency: toFloat(r.frequency),
    leads_meta: extractLeads(r.actions),
    daily_budget_cents: isToday ? toInt(adsetMeta.daily_budget) : null,
    lifetime_budget_cents: isToday ? toInt(adsetMeta.lifetime_budget) : null,
    budget_remaining_cents: isToday ? toInt(adsetMeta.budget_remaining) : null,
    raw_payload: r,
    fetched_at: new Date().toISOString(),
  });
}

return [{ json: { rows } }];
